-- Domain data snapshot — 2026-03-02.
-- Replaces the dynamic local-truth rebuild system.
-- Applied once: local (via db reset) and remote (via db push).
-- The sales table is intentionally excluded: it is managed by auth triggers.

SET session_replication_role = replica; -- bypass FK/trigger checks during load

TRUNCATE TABLE
  public.financial_document_cash_allocations,
  public.financial_document_project_allocations,
  public.cash_movements,
  public.financial_documents,
  public.project_contacts,
  public.client_notes,
  public.client_tasks,
  public.expenses,
  public.payments,
  public.services,
  public.quotes,
  public.projects,
  public.contacts,
  public.clients,
  public.tags,
  public.settings
CASCADE;

SELECT pg_catalog.setval('public.contacts_id_seq', 1, true);
SELECT pg_catalog.setval('public.tags_id_seq', 1, false);

SET session_replication_role = DEFAULT;
